L6: function quickSort(arr: number[]): number[] {
L7:   // 基线条件：数组长度小于等于1时直接返回
L8:   if (arr.length <= 1) {
L9:     return arr;
L10:   }
L11:   
L12:   // 选择基准元素（这里选择中间元素）
L13:   const pivot = arr[Math.floor(arr.length / 2)];
L14:   const left: number[] = [];
L15:   const right: number[] = [];
L16:   const equal: number[] = [];
L17:   
L18:   // 将元素按与基准的大小关系分组
L19:   for (const element of arr) {
L20:     if (element < pivot) {
L21:       left.push(element);
L22:     } else if (element > pivot) {
L23:       right.push(element);
L24:     } else {
L25:       equal.push(element);
L26:     }
L27:   }
L28:   
L29:   // 递归排序左右子数组，并合并结果
L30:   return [...quickSort(left), ...equal, ...quickSort(right)];
L31: }
