L35: console.log('排序后: ', quickSort([3, 6, 2, 8, 1, 9])); // 输出: [1, 2, 3, 6, 8, 9]
L36: 
L37: console.log('\n排序前: [5, 5, 5]');
L38: console.log('排序后: ', quickSort([5, 5, 5])); // 输出: [5, 5, 5]
